ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/filmmaking#>
PREFIX p: <http://ambrosia.example.org/filmmaking/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?title ?genre ?release_year ?name WHERE {
  ?movie a :Movies .
  ?director a :Directors .
  ?movie p:hasDirector ?director .
  ?movie p:title ?title .
  ?movie p:genre ?genre .
  ?movie p:release_year ?release_year .
  ?director p:name ?name .
} }
  component_2: { SELECT ?title ?genre ?release_year ?name WHERE {
  ?movie a :Movies .
  ?studio a :Studio .
  ?movie p:hasStudio ?studio .
  ?movie p:title ?title .
  ?movie p:genre ?genre .
  ?movie p:release_year ?release_year .
  ?studio p:name ?name .
} }
  full: { SELECT ?title ?genre ?release_year ?name ?name2 WHERE {
  ?movie a :Movies .
  ?studio a :Studio .
  ?movie p:hasStudio ?studio .
  ?director a :Directors .
  ?movie p:hasDirector ?director .
  ?movie p:title ?title .
  ?movie p:genre ?genre .
  ?movie p:release_year ?release_year .
  ?studio p:name ?name .
  ?director p:name ?name2 .
} }
}
